import{_ as e,o as r,c as n,a2 as a}from"./chunks/framework.qS7v0XB7.js";const m=JSON.parse('{"title":"Netherlands — Country Profile","description":"Comprehensive guide to the Netherlands for transgender relocation: legal recognition, healthcare, cost of living, visa pathways, community, and risks.","frontmatter":{"layout":"doc","title":"Netherlands — Country Profile","description":"Comprehensive guide to the Netherlands for transgender relocation: legal recognition, healthcare, cost of living, visa pathways, community, and risks."},"headers":[],"relativePath":"countries/netherlands/index.md","filePath":"countries/netherlands/index.md","lastUpdated":1780601195000}'),o={name:"countries/netherlands/index.md"};function i(s,t,d,l,h,c){return r(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="🇳🇱-netherlands" tabindex="-1"><span style="color:#ff6600;">🇳🇱 Netherlands</span> <a class="header-anchor" href="#🇳🇱-netherlands" aria-label="Permalink to &quot;&lt;span style=&quot;color: #ff6600;&quot;&gt;🇳🇱 Netherlands&lt;/span&gt;&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Capital</strong></td><td>Amsterdam</td></tr><tr><td><strong>Population</strong></td><td>~17.7 million</td></tr><tr><td><strong>Language</strong></td><td>Dutch (English near-universally spoken)</td></tr><tr><td><strong>Currency</strong></td><td>Euro (EUR)</td></tr><tr><td><strong>EU Member</strong></td><td>Yes</td></tr><tr><td><strong>Equaldex Score</strong></td><td>94</td></tr><tr><td><strong>Trans-Specific Rating</strong></td><td>5/5</td></tr><tr><td><strong>Last Verified</strong></td><td>June 2026</td></tr></tbody></table><h2 id="legal-overview" tabindex="-1">Legal Overview <a class="header-anchor" href="#legal-overview" aria-label="Permalink to &quot;Legal Overview&quot;">​</a></h2><ul><li><strong>Gender Recognition:</strong> Self-ID since 2014. Adults can change legal gender by submitting a declaration to the municipality. No medical requirements, no surgery, no therapy. One of the earliest European countries to adopt self-ID.</li><li><strong>Anti-Discrimination Law:</strong> Comprehensive. The Algemene wet gelijke behandeling (AWGB, 1994) covers gender in employment, housing, and services. Enforcement is active through the College voor de Rechten van de Mens.</li><li><strong>Hate Crime Laws:</strong> Gender identity is protected in criminal code sentencing.</li><li><strong>Same-Sex Marriage:</strong> Legal since 2001 (first country in the world).</li><li><strong>Conversion Therapy:</strong> Banned (2025).</li></ul><h2 id="healthcare-reality" tabindex="-1">Healthcare Reality <a class="header-anchor" href="#healthcare-reality" aria-label="Permalink to &quot;Healthcare Reality&quot;">​</a></h2><ul><li><strong>HRT Access:</strong> Informed consent is the standard. Many GPs prescribe HRT directly. Specialist gender clinics exist but are not required for access.</li><li><strong>HRT Cost:</strong> Covered by public insurance (basisverzekering) after deductible (€385/year in 2025). Monthly cost: effectively €30–60 after deductible.</li><li><strong>Wait times:</strong> 2–8 weeks for GP. Gender clinics (Amsterdam UMC, Radboud UMC) have 6–12 month wait lists.</li><li><strong>Surgery:</strong> Public insurance covers gender-affirming surgeries with prior approval. Wait times: 6–18 months.</li><li><strong>Key clinics:</strong> Amsterdam UMC (location VUmc), Radboud UMC (Nijmegen), UMC Groningen.</li></ul><h2 id="where-to-live" tabindex="-1">Where to Live <a class="header-anchor" href="#where-to-live" aria-label="Permalink to &quot;Where to Live&quot;">​</a></h2><ul><li><strong>Amsterdam:</strong> Largest trans community. Very expensive. 1-bedroom: €1,200–1,800/month.</li><li><strong>Utrecht:</strong> Strong community. Popular with students and professionals. 1-bedroom: €1,000–1,500/month.</li><li><strong>Rotterdam:</strong> Largest city after Amsterdam. Good trans community. 1-bedroom: €900–1,400/month.</li><li><strong>The Hague (Den Haag):</strong> International city. Moderate community. 1-bedroom: €900–1,400/month.</li><li><strong>Eindhoven:</strong> Smaller scene. 1-bedroom: €800–1,200/month.</li><li><strong>Rural Netherlands:</strong> Less trans community. Housing shortage less severe but still exists.</li></ul><p><strong>Monthly budget (Amsterdam):</strong> €2,000–3,500.</p><h2 id="visa-pathways" tabindex="-1">Visa Pathways <a class="header-anchor" href="#visa-pathways" aria-label="Permalink to &quot;Visa Pathways&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Income Req.</th><th>Processing</th><th>Leads to PR?</th></tr></thead><tbody><tr><td>Work Visa (GVVA)</td><td>Job offer required</td><td>2–4 months</td><td>Yes</td></tr><tr><td>EU Blue Card</td><td>€5,688/month (2025)</td><td>2–4 months</td><td>Yes</td></tr><tr><td>DAFT (US citizens)</td><td>€4,500 investment</td><td>2–4 weeks</td><td>Yes</td></tr><tr><td>Student Visa</td><td>Proof of funds</td><td>1–3 months</td><td>Yes (orientation year)</td></tr><tr><td>EU Freedom of Movement</td><td>N/A</td><td>Immediate</td><td>Yes</td></tr><tr><td>Asylum</td><td>N/A</td><td>6–18 months</td><td>Yes (60–75% grant rate)</td></tr></tbody></table><h2 id="known-risks" tabindex="-1">Known Risks <a class="header-anchor" href="#known-risks" aria-label="Permalink to &quot;Known Risks&quot;">​</a></h2><ol><li><strong>Extremely competitive housing market</strong> — finding an apartment, especially in Amsterdam, can take 3–6 months</li><li><strong>Very high cost of living</strong> — one of the most expensive countries in Europe</li><li><strong>Housing crisis</strong> affects all major cities</li><li><strong>Weather:</strong> Grey, rainy, and overcast for much of the year</li><li><strong>Healthcare deductible:</strong> €385/year (2025) must be paid before insurance covers most care</li></ol><p><em>Sources: COC Nederland, Transgender Netwerk Nederland, TGEU, Equaldex. Last verified: June 2026.</em></p>',14)])])}const u=e(o,[["render",i]]);export{m as __pageData,u as default};
